import{c as n,Q as s,j as a,m as o}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"第17章 入职后6个月：从\\"混进去\\"到\\"站得住\\"","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"zh/part5-career/chapter19.md","filePath":"zh/part5-career/chapter19.md"}'),p={name:"zh/part5-career/chapter19.md"};function l(r,t,e,i,u,q){return s(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="第17章-入职后6个月-从-混进去-到-站得住" tabindex="-1">第17章 入职后6个月：从&quot;混进去&quot;到&quot;站得住&quot; <a class="header-anchor" href="#第17章-入职后6个月-从-混进去-到-站得住" aria-label="Permalink to &quot;第17章 入职后6个月：从&quot;混进去&quot;到&quot;站得住&quot;&quot;">​</a></h1><h2 id="本章你能带走什么" tabindex="-1">本章你能带走什么 <a class="header-anchor" href="#本章你能带走什么" aria-label="Permalink to &quot;本章你能带走什么&quot;">​</a></h2><p>恭喜你，闯过了入职前30天的生死局。</p><p>你现在应该已经：环境跑通了、代码读顺了、第一个任务交出去了、团队的人也认全了。你感觉自己&quot;活下来了&quot;，甚至有点小得意。</p><p>但我必须提醒你：<strong>前30天只是拿到了参赛资格，真正的比赛才刚刚开始</strong>。</p><p>很多人倒在入职后第2-3个月。不是因为他们能力不行，而是因为他们犯了一个致命错误——<strong>以为自己已经&quot;站稳了&quot;，开始躺在功劳簿上睡觉</strong>。</p><p>接下来的6个月，是你从&quot;试用期菜鸟&quot;变成&quot;正式员工&quot;再到&quot;团队核心&quot;的关键期。这段时间你做的选择，将决定你三年后的职业高度。</p><p>具体来说，这章会帮你解决四个核心问题：</p><ul><li><strong>补课路线</strong>：入职后发现短板太多，该从哪里补起？时间有限，怎么分配精力？</li><li><strong>成长路径</strong>：从&quot;领导让我做什么我就做什么&quot;到&quot;我知道该做什么并且能做出来&quot;，这条路怎么走？</li><li><strong>持续学习</strong>：AI技术三个月一变，怎么跟得上又不会被信息洪水淹死？</li><li><strong>职业天花板</strong>：AI应用开发的天花板在哪？35岁危机怎么破？</li></ul><p>读完这章，你会有一张清晰的&quot;入职后6个月作战地图&quot;。</p><hr><h2 id="_17-1-补课路线-缺什么补什么" tabindex="-1">17.1 补课路线：缺什么补什么 <a class="header-anchor" href="#_17-1-补课路线-缺什么补什么" aria-label="Permalink to &quot;17.1 补课路线：缺什么补什么&quot;">​</a></h2><h3 id="先诊断-再开药" tabindex="-1">先诊断，再开药 <a class="header-anchor" href="#先诊断-再开药" aria-label="Permalink to &quot;先诊断，再开药&quot;">​</a></h3><p>入职第一个月，你大概会经历一个&quot;自信心爆棚→发现差距→焦虑&quot;的过山车。</p><p>第一周：&quot;我能行！我要大干一场！&quot; 第二周：&quot;咦，这个代码怎么这么复杂？&quot; 第三周：&quot;完了，我什么都不会。&quot; 第四周：&quot;好像也没那么糟，但问题好多，从哪补起？&quot;</p><p>如果你现在正处于&quot;问题好多，从哪补起&quot;的阶段，恭喜你，这是正常状态。</p><p>现在最关键的问题是：<strong>你的时间和精力是有限的，不可能把所有短板都补齐。你需要一张&quot;补课地图&quot;，告诉你该往哪使劲</strong>。</p><h3 id="四象限法则-给短板排优先级" tabindex="-1">四象限法则：给短板排优先级 <a class="header-anchor" href="#四象限法则-给短板排优先级" aria-label="Permalink to &quot;四象限法则：给短板排优先级&quot;">​</a></h3><p>我见过太多人陷入&quot;全面补课&quot;的陷阱——今天学点Python，明天看点AI基础，后天又去刷机器学习视频。结果三个月过去了，什么都会一点，什么都不精。</p><p>正确的做法是：<strong>用四象限法则给短板排优先级</strong>。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    岗位急需</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>          ┌─────────────┼─────────────┐</span></span>
<span class="line"><span>          │             │             │</span></span>
<span class="line"><span>   低频   │   第三象限   │   第二象限   │</span></span>
<span class="line"><span>  慢补    │  &quot;先放着&quot;   │  &quot;优先补课&quot;  │</span></span>
<span class="line"><span>          │             │             │</span></span>
<span class="line"><span>          ├─────────────┼─────────────┤</span></span>
<span class="line"><span>          │             │             │</span></span>
<span class="line"><span>   高频   │   第四象限   │   第一象限   │</span></span>
<span class="line"><span>  快补    │  &quot;有空再说&quot;  │  &quot;立刻补&quot;    │</span></span>
<span class="line"><span>          │             │             │</span></span>
<span class="line"><span>          └─────────────┴─────────────┘</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                    岗位急需</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p><strong>第一象限：高频+急需 = 立刻补</strong></p><p>这类技能是&quot;不会就干不了活&quot;的。比如：</p><ul><li>你负责RAG模块，但不懂向量检索</li><li>你要对接LLM API，但不会处理异步请求</li><li>你的代码需要上容器，但Docker只会&quot;docker run&quot;</li></ul><p>这些技能不需要系统学习，直接看官方文档或教程，跟着做一遍，够用就行。</p><p><strong>第二象限：低频+急需 = 优先补</strong></p><p>这类是&quot;不常用但很重要&quot;的。比如：</p><ul><li>团队用的监控系统，你之前没接触过</li><li>数据库选型需要做决策，你不太懂</li><li>代码评审涉及安全规范，你没系统学过</li></ul><p>这些需要稍微系统一点的学习，但不用钻太深，知道&quot;是什么&quot;和&quot;怎么用&quot;就够了。</p><p><strong>第三象限：低频+不急需 = 先放着</strong></p><p>这类是&quot;学了也用不上&quot;的。比如：</p><ul><li>你的团队用PyTorch，但工作主要是调API</li><li>公司不用Kubernetes，但你听说很火</li><li>AI底层的Transformer架构，纯研究向</li></ul><p>这些等有空再说，或者永远不说。</p><p><strong>第四象限：高频+不急需 = 有空再说</strong></p><p>这类是&quot;有用但可以缓一缓&quot;的。比如：</p><ul><li>代码规范和设计模式</li><li>性能优化和架构设计</li><li>开源社区的最新动态</li></ul><p>这些可以慢慢积累，但不要在入职初期分散精力。</p><h3 id="实战案例-三个月补课计划" tabindex="-1">实战案例：三个月补课计划 <a class="header-anchor" href="#实战案例-三个月补课计划" aria-label="Permalink to &quot;实战案例：三个月补课计划&quot;">​</a></h3><p>我给你讲一个真实的例子。</p><p>小张入职了一家电商公司的AI应用开发岗，负责智能客服模块。他的情况是：</p><p><strong>已知技能</strong>：Python基础、写过几个LangChain demo、了解LLM基本概念</p><p><strong>短板清单</strong>：</p><ol><li>没接触过生产级RAG代码，不知道怎么优化检索效果</li><li>不懂FastAPI，之前只用Flask</li><li>Docker只会&quot;docker run -it&quot;</li><li>不懂Redis，不知道缓存是干什么的</li><li>团队用Kubernetes，他完全不会</li><li>机器学习基础几乎为零</li></ol><p>按四象限分析：</p><table tabindex="0"><thead><tr><th>短板</th><th>频率</th><th>急需</th><th>象限</th><th>策略</th></tr></thead><tbody><tr><td>RAG优化</td><td>高</td><td>是</td><td>第一</td><td>立刻补</td></tr><tr><td>FastAPI</td><td>高</td><td>是</td><td>第一</td><td>立刻补</td></tr><tr><td>Redis缓存</td><td>高</td><td>是</td><td>第一</td><td>立刻补</td></tr><tr><td>Docker进阶</td><td>高</td><td>否</td><td>第四</td><td>有空补</td></tr><tr><td>K8s</td><td>低</td><td>否</td><td>第三</td><td>先放</td></tr><tr><td>ML基础</td><td>低</td><td>否</td><td>第三</td><td>先放</td></tr></tbody></table><p>他的三个月补课计划是这样的：</p><p><strong>第一个月：死磕RAG</strong></p><p>目标：能独立处理一个RAG相关的任务</p><p>具体行动：</p><ul><li>每天花1小时读团队现有的RAG代码，搞懂切块策略、检索逻辑</li><li>周末复现一个开源RAG项目，对比团队方案找差异</li><li>主动接手一个小任务：优化某个检索场景的top_k参数</li></ul><p><strong>第二个月：FastAPI+Redis双线作战</strong></p><p>目标：能独立写一个AI服务的API接口</p><p>具体行动：</p><ul><li>把团队的FastAPI代码拿来，改几个接口，理解框架用法</li><li>Redis只需要知道两个场景：缓存向量搜索结果、缓存对话历史</li><li>动手做一个&quot;带缓存的RAG服务&quot;，实战中学习</li></ul><p><strong>第三个月：补生态</strong></p><p>目标：理解AI服务的完整生命周期</p><p>具体行动：</p><ul><li>学Dockerfile怎么写，Kubernetes的yaml文件能看懂</li><li>参与一次部署流程，跟运维同事学学</li><li>开始关注团队的监控告警，理解&quot;生产环境&quot;长什么样</li></ul><p>三个月后，小张能独立负责一个RAG场景的开发和优化。Docker和K8s虽然还是半吊子，但够用了；ML基础暂时没补，也不影响干活。</p><p><strong>记住：补课的目标不是&quot;变成全能选手&quot;，而是&quot;能在关键路径上不拖后腿&quot;</strong>。</p><h3 id="补课的资源选择" tabindex="-1">补课的资源选择 <a class="header-anchor" href="#补课的资源选择" aria-label="Permalink to &quot;补课的资源选择&quot;">​</a></h3><p>我知道你想问：&quot;那我上哪学？&quot;</p><p>给你一个优先级排序：</p><p><strong>1. 团队内部文档和代码（优先级最高）</strong></p><p>你团队写的东西是最贴合实际的。学这个效率最高、见效最快。</p><p><strong>2. 官方文档（优先级第二）</strong></p><p>学Redis，去Redis官方文档；学FastAPI，去FastAPI官方文档。官方文档通常比二手教程更准确、更及时。</p><p><strong>3. 官方教程和示例（优先级第三）</strong></p><p>LangChain官方有大量Jupyter Notebook，动手跟着做一遍，比看十篇博客都强。</p><p><strong>4. 高质量博客/视频（优先级第四）</strong></p><p>选一两个你信任的博主，关注他们的更新。但要克制——不要收藏夹吃灰。</p><p><strong>5. 书籍（优先级最低）</strong></p><p>不是说书不好，而是书籍的更新速度赶不上AI领域的变化。除非你要系统打基础，否则先别买书。</p><hr><h2 id="_17-2-从执行者到owner的成长路径" tabindex="-1">17.2 从执行者到Owner的成长路径 <a class="header-anchor" href="#_17-2-从执行者到owner的成长路径" aria-label="Permalink to &quot;17.2 从执行者到Owner的成长路径&quot;">​</a></h2><h3 id="执行者、协作者、owner-你现在在哪一层" tabindex="-1">执行者、协作者、Owner：你现在在哪一层？ <a class="header-anchor" href="#执行者、协作者、owner-你现在在哪一层" aria-label="Permalink to &quot;执行者、协作者、Owner：你现在在哪一层？&quot;">​</a></h3><p>入职前6个月，大多数人会经历三个阶段的进化：</p><p><strong>第一阶段：执行者（Entry Level）</strong></p><p>状态：领导说做什么我就做什么，做完交差。</p><p>这个阶段的核心任务是<strong>学习</strong>——学团队的技术栈、学业务流程、学团队协作方式。你的价值来自&quot;执行&quot;，把分配的任务按时按质完成就是好表现。</p><p><strong>第二阶段：协作者（Mid Level）</strong></p><p>状态：不仅能完成任务，还能主动发现问题、提出建议。</p><p>这个阶段的核心任务是<strong>贡献</strong>——不仅执行，还开始输出观点。你会发现代码里的一些问题、流程里的一些低效，并主动提出来。你的价值来自&quot;发现问题+解决问题&quot;。</p><p><strong>第三阶段：Owner（Senior Level）</strong></p><p>状态：某个模块/项目完全由你负责，你知道该做什么、怎么做、什么时候做。</p><p>这个阶段的核心任务是<strong>规划</strong>——你不仅解决问题，还定义问题。你知道业务目标是什么、技术债务在哪、优先级怎么排。你对某个领域的产出负责。</p><h3 id="怎么从执行者进化到owner" tabindex="-1">怎么从执行者进化到Owner？ <a class="header-anchor" href="#怎么从执行者进化到owner" aria-label="Permalink to &quot;怎么从执行者进化到Owner？&quot;">​</a></h3><p>这个进化不是自动发生的。很多人做了一年还是&quot;高级执行者&quot;——能完成任务，但一直在等指令。</p><p>从执行者到Owner，有几个关键的跃迁点：</p><p><strong>跃迁点1：从&quot;做完&quot;到&quot;做好&quot;</strong></p><p>执行者的心态是&quot;做完交差&quot;。Owner的心态是&quot;做完还要管&quot;。</p><p>举个例子：</p><blockquote><p>领导让你写一个RAG接口，你写完了，返回结果正常。任务完成了吗？从执行者角度，完成了。从Owner角度，才刚刚开始。</p><p>Owner会想：</p><ul><li>这个接口的延迟是多少？能不能优化？</li><li>如果向量数据库挂了会怎样？有没有兜底？</li><li>这个接口能承受多少并发？需不需要限流？</li><li>其他模块会不会用到这个接口？需不需要考虑兼容？</li></ul></blockquote><p>多做一步，往往就是平庸和优秀的分界线。</p><p><strong>跃迁点2：从&quot;被动接任务&quot;到&quot;主动发现问题&quot;</strong></p><p>执行者的节奏是&quot;等任务→接任务→做任务&quot;。Owner的节奏是&quot;主动看→主动规划→主动推进&quot;。</p><p>怎么培养主动发现问题的能力？<strong>每天花10分钟&quot;巡逻&quot;你的模块</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ 今天有新的告警吗？</span></span>
<span class="line"><span>□ 同事有没有在群里提过我的模块的问题？</span></span>
<span class="line"><span>□ 监控面板有没有异常？</span></span>
<span class="line"><span>□ 我的代码有没有技术债务需要还？</span></span>
<span class="line"><span>□ 有没有可以优化的点？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这个习惯看起来很小，但坚持三个月，你会发现自己对系统的理解远超同龄人。</p><p><strong>跃迁点3：从&quot;一个人干&quot;到&quot;带动别人干&quot;</strong></p><p>Owner不意味着单打独斗，恰恰相反——Owner的核心能力是<strong>协调和放大</strong>。</p><p>你会开始：</p><ul><li>帮助新人熟悉你的模块</li><li>推动技术方案的讨论和落地</li><li>组织code review，推动代码质量提升</li><li>参与招聘，面试候选人</li></ul><p>这些事情都在&quot;写代码&quot;之外，但都是Owner必须具备的能力。</p><p><strong>跃迁点4：从&quot;完成任务&quot;到&quot;定义问题&quot;</strong></p><p>最高级的跃迁是：你不再等别人给你问题，你自己去发现问题、定义问题、推动解决。</p><p>比如你发现团队的RAG检索效果不稳定，但你没等领导安排，自己就开始调研、测试、提出优化方案、推动落地。</p><p>这种&quot;自驱力&quot;是Owner的标志性特征。</p><h3 id="_6个月成长路线图" tabindex="-1">6个月成长路线图 <a class="header-anchor" href="#_6个月成长路线图" aria-label="Permalink to &quot;6个月成长路线图&quot;">​</a></h3><p>我把&quot;入职后6个月&quot;拆成一个具体的成长路线图：</p><p><strong>Month 1-2：执行者阶段</strong></p><p>目标：能独立完成分配的任务</p><p>关键行动：</p><ul><li>掌握核心模块的代码和业务逻辑</li><li>按时按质完成每个任务</li><li>养成&quot;做完多检查一遍&quot;的习惯</li><li>主动问问题，不要自己憋着</li></ul><p>成长标志：Leader不需要追你的进度，你自己知道什么时候该交什么。</p><p><strong>Month 3-4：协作者阶段</strong></p><p>目标：能主动发现和解决问题</p><p>关键行动：</p><ul><li>每天巡逻自己的模块</li><li>记录和解决遇到的问题</li><li>开始参与技术方案讨论</li><li>尝试给别人提改进建议</li></ul><p>成长标志：你会主动提出一些Leader没想到的问题，并且有可行的解决方案。</p><p><strong>Month 5-6：Owner意识萌芽</strong></p><p>目标：开始对某个细分领域负责</p><p>关键行动：</p><ul><li>主动认领一个子模块的维护责任</li><li>开始关注模块的长期健康度</li><li>尝试独立推动一个小项目</li><li>学会向上管理：主动同步进度、主动要资源</li></ul><p>成长标志：Leader开始把一些&quot;你没做过但相信你能搞定&quot;的任务交给你。</p><h3 id="实战案例-从执行者到owner的真实路径" tabindex="-1">实战案例：从执行者到Owner的真实路径 <a class="header-anchor" href="#实战案例-从执行者到owner的真实路径" aria-label="Permalink to &quot;实战案例：从执行者到Owner的真实路径&quot;">​</a></h3><p>小李入职后的成长路径很有意思。</p><p><strong>第一个月</strong>：Leader给他分配任务，他埋头干完就算。代码质量还行，但从来不问&quot;为什么这么做&quot;。</p><p><strong>第三个月</strong>：他开始观察团队的代码，发现有些地方写得不太好。他主动给Leader发了一条消息：&quot;我发现我们的Prompt模板管理比较散乱，后续可能不好维护，我建议统一管理，您看要不要搞？&quot;Leader说&quot;可以，你来牵头&quot;。</p><p>这是他第一次&quot;定义问题&quot;。虽然只是个小的改进，但他开始从一个被动执行者变成主动贡献者。</p><p><strong>第五个月</strong>：团队要上线一个新功能，Leader问谁愿意负责。小李犹豫了一下，说&quot;我来试试&quot;。他第一次当Owner：从需求分析、技术方案设计、任务分配、进度管理到最终交付，全链路负责。</p><p>过程很痛苦——他低估了复杂度，进度delay了两次；跨团队沟通时踩了很多坑；Code Review被怼得很惨。但他咬着牙走完了全程。</p><p><strong>第六个月复盘</strong>：Leader对他的评价是&quot;进步超出预期&quot;。不是因为他的代码写得有多好，而是因为他有Ownership意识——出了问题他会主动追，不把球踢给别人。</p><p>现在小李是团队里某条核心业务的Owner，比他早入职半年的同事还在等任务分配，他的成长速度已经超过了很多人。</p><p><strong>关键启示：成长不是等来的，是自己争取来的。主动认领任务、主动发现问题、主动推动改进——这三件事做与不做，六个月后就是两种完全不同的人。</strong></p><hr><h2 id="_17-3-持续学习-跟上ai领域的快速迭代" tabindex="-1">17.3 持续学习：跟上AI领域的快速迭代 <a class="header-anchor" href="#_17-3-持续学习-跟上ai领域的快速迭代" aria-label="Permalink to &quot;17.3 持续学习：跟上AI领域的快速迭代&quot;">​</a></h2><h3 id="为什么你学不过来" tabindex="-1">为什么你学不过来？ <a class="header-anchor" href="#为什么你学不过来" aria-label="Permalink to &quot;为什么你学不过来？&quot;">​</a></h3><p>AI领域有一个独特的悖论：<strong>知识增长的速度，远超个人学习吸收的速度</strong>。</p><p>2024年初你可能刚搞懂LangChain，年底LangGraph就出来了。2025年你可能刚上手Agent开发，Multi-Agent又成了标配。你永远在追赶，永远追不上。</p><p>这不是你不行，这是行业特性。</p><p>我见过太多人被这个悖论打败——他们陷入&quot;学习焦虑&quot;，每天刷无数技术博客、收藏无数教程、报无数课程，结果什么都没学会，反而把自己搞得很累。</p><p>这里我给你一套&quot;持续学习&quot;的方法论，帮你从信息焦虑中解放出来。</p><h3 id="建立-输入-处理-输出-的学习系统" tabindex="-1">建立&quot;输入-处理-输出&quot;的学习系统 <a class="header-anchor" href="#建立-输入-处理-输出-的学习系统" aria-label="Permalink to &quot;建立&quot;输入-处理-输出&quot;的学习系统&quot;">​</a></h3><p>很多人学习效率低，不是因为不够努力，而是因为<strong>学习方式不对</strong>。</p><p>他们的学习流程是这样的：</p><ol><li>看到一个好东西，收藏</li><li>又看到一个，收藏</li><li>收藏夹有500篇文章，再也不看</li></ol><p>这是&quot;只进不出&quot;的囤积式学习，效率为零。</p><p>正确的学习系统有三个环节：</p><p><strong>1. 输入：筛选，不是越多越好</strong></p><p>AI领域每天产出的内容足够你看一辈子。你要做的是<strong>筛选</strong>，不是&quot;全部吸收&quot;。</p><p>筛选原则：</p><ul><li><strong>跟工作相关的优先</strong>：你现在在做的RAG，就多看RAG；你在做Agent，就多看Agent</li><li><strong>一手资料优先</strong>：官方文档、技术论文 &gt; 二手博客 &gt; 三手解读</li><li><strong>质量重于数量</strong>：一篇深度好文，胜过十篇浅尝辄止</li></ul><p>具体操作：</p><ul><li>关注3-5个你信任的技术博主/公众号</li><li>加入1-2个高质量的技术社群</li><li>每天给自己设定&quot;技术阅读时间上限&quot;（比如30分钟）</li></ul><p><strong>2. 处理：消化，不是存起来</strong></p><p>读到一个好东西，不要只是&quot;收藏了&quot;。当场消化：</p><ul><li>用自己的话复述一遍（写200字笔记）</li><li>思考这东西能不能用到工作里</li><li>如果能用，计划什么时候用</li></ul><p>收藏夹里超过一个月没看的文章，90%的概率你再也不会看了。所以<strong>当场消化，别指望以后再复习</strong>。</p><p><strong>3. 输出：分享，输出倒逼输入</strong></p><p>学习的最佳方式是<strong>教别人</strong>。</p><p>你不需要开个技术博客去&quot;打造个人IP&quot;——那太累了。你只需要：</p><ul><li>在团队内做一次技术分享</li><li>在群里回答一个同行的问题</li><li>写一份内部文档，记录你学到的东西</li></ul><p>输出的过程会逼你把知识整理清楚。很多你以为&quot;懂了&quot;的东西，说出来才发现&quot;其实没懂&quot;。</p><h3 id="ai技术迭代的应对策略" tabindex="-1">AI技术迭代的应对策略 <a class="header-anchor" href="#ai技术迭代的应对策略" aria-label="Permalink to &quot;AI技术迭代的应对策略&quot;">​</a></h3><p>AI技术的迭代速度确实很快，但你可以用一套策略来应对：</p><p><strong>策略1：学底层，不学表层</strong></p><p>表层的东西变化快，底层的东西变化慢。</p><p>比如：</p><ul><li>LangChain的API可能年年变，但&quot;Chain&quot;这个概念不会变</li><li>GPT-4的调用方式可能调整，但&quot;LLM调用&quot;的核心逻辑不会变</li><li>新的Agent框架层出不穷，但&quot;Agent = LLM + Tools + Memory&quot;这个公式不会变</li></ul><p>学底层让你的知识有更长的有效期。</p><p><strong>策略2：跟进官方，不追热点</strong></p><p>官方发布的内容是&quot;信号&quot;，二手解读是&quot;噪声&quot;。</p><p>每个框架/工具的官方博客、GitHub Release Notes是必看的。其他技术博主的内容可以作为辅助参考，但不要把大量时间花在看二手解读上。</p><p><strong>策略3：深入一个，不要浅尝十个</strong></p><p>在一个领域深入理解，比在十个领域蜻蜓点水更有价值。</p><p>一个例子：</p><ul><li>深入RAG：向量检索、混合检索、重排序、Query改写、知识图谱增强...一个方向可以挖很深</li><li>浅尝RAG：知道RAG是什么，能跑demo，仅此而已</li></ul><p>企业在面试时，更看重&quot;你深入的那个点&quot;有多深，而不是&quot;你听说过的技术&quot;有多少。</p><p><strong>策略4：用项目驱动学习</strong></p><p>最好的学习时机是&quot;当你需要用它的时候&quot;。</p><p>不要为了&quot;学习&quot;而学习，带着问题学、带着项目学，效率高十倍。</p><h3 id="建立你的-技术雷达" tabindex="-1">建立你的&quot;技术雷达&quot; <a class="header-anchor" href="#建立你的-技术雷达" aria-label="Permalink to &quot;建立你的&quot;技术雷达&quot;&quot;">​</a></h3><p>我建议每个AI开发者建立自己的&quot;技术雷达&quot;——定期扫描领域动态，但不过度沉迷。</p><p><strong>每月一次的雷达扫描清单</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ LangChain/LlamaIndex官方博客：有什么新特性？</span></span>
<span class="line"><span>□ Hugging Face趋势：哪些模型在流行？</span></span>
<span class="line"><span>□ GitHub Trending：有哪些新开源项目值得关注？</span></span>
<span class="line"><span>□ 团队技术债务：我们系统有什么需要升级的？</span></span>
<span class="line"><span>□ 业界动态：有没有影响我们业务的技术变化？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>每次扫描不要超过1小时。重点不是&quot;看完所有东西&quot;，而是&quot;知道外面在发生什么，同时不被信息淹没&quot;。</p><hr><h2 id="_17-4-职业天花板与突破方向" tabindex="-1">17.4 职业天花板与突破方向 <a class="header-anchor" href="#_17-4-职业天花板与突破方向" aria-label="Permalink to &quot;17.4 职业天花板与突破方向&quot;">​</a></h2><h3 id="ai应用开发的天花板在哪" tabindex="-1">AI应用开发的天花板在哪？ <a class="header-anchor" href="#ai应用开发的天花板在哪" aria-label="Permalink to &quot;AI应用开发的天花板在哪？&quot;">​</a></h3><p>说实话，AI应用开发的&quot;天花板&quot;问题，是很多从业者迟早要面对的焦虑。</p><p>这个焦虑的本质是：<strong>35岁以后，我还写代码吗？我能做什么？</strong></p><p>在讨论天花板之前，先说一个好消息：<strong>AI应用开发的&quot;天花板&quot;比大多数技术岗位高，而且还在不断抬高</strong>。</p><p>为什么？因为AI应用开发是<strong>业务+技术的交叉点</strong>，这个位置天然抗&quot;纯技术岗&quot;的中年危机。</p><p>但我也不想给你灌鸡汤。天花板确实存在，只是没那么低。让我给你分析几条常见的职业路径，以及各自的突破方向。</p><h3 id="路径一-技术专家路线" tabindex="-1">路径一：技术专家路线 <a class="header-anchor" href="#路径一-技术专家路线" aria-label="Permalink to &quot;路径一：技术专家路线&quot;">​</a></h3><p><strong>描述</strong>：成为某个AI技术领域的专家，比如RAG专家、Agent架构师、LLM优化专家。</p><p><strong>特点</strong>：靠技术深度吃饭，35岁以后仍然有竞争力。</p><p><strong>怎么走</strong>：</p><ol><li><strong>选择一个方向深挖</strong>：不要什么都学，选一个方向（比如RAG）死磕，成为团队里最懂这个方向的人</li><li><strong>输出内容建立影响力</strong>：写技术博客、做技术分享、参与开源，让行业知道你是这个方向的专家</li><li><strong>解决难题积累声望</strong>：主动接手团队里最难的RAG问题，一次次解决&quot;没人搞得定&quot;的问题</li></ol><p><strong>天花板</strong>：技术专家的天花板可以很高。顶级AI应用公司的&quot;首席工程师&quot;、&quot;Fellow&quot;级别，年薪可以过百万甚至更高，而且越老越值钱——因为你的经验是踩坑踩出来的。</p><h3 id="路径二-技术管理路线" tabindex="-1">路径二：技术管理路线 <a class="header-anchor" href="#路径二-技术管理路线" aria-label="Permalink to &quot;路径二：技术管理路线&quot;">​</a></h3><p><strong>描述</strong>：从技术岗转向管理岗，从&quot;自己写代码&quot;变成&quot;带人写代码&quot;。</p><p><strong>特点</strong>：需要的能力从&quot;技术能力&quot;变成&quot;技术+沟通+规划+协调&quot;。</p><p><strong>怎么走</strong>：</p><ol><li><strong>先当&quot;隐性Owner&quot;</strong>：在当Manager之前，先对某个模块负完全责任，练习协调和规划能力</li><li><strong>主动承担&quot;带人&quot;职责</strong>：帮助新人熟悉代码、组织code review、推动技术分享——这些是管理者的日常</li><li><strong>观察你所在团队/公司的Manager</strong>：看看他们每天在做什么，判断自己喜不喜欢、擅不擅长</li></ol><p><strong>天花板</strong>：管理路线的好处是&quot;天花板高+路径清晰&quot;。大厂的P8/P9及以上，基本都是管理或技术管理路线。但坏处是僧多粥少，而且管理工作不一定适合每个人。</p><h3 id="路径三-产品-业务路线" tabindex="-1">路径三：产品/业务路线 <a class="header-anchor" href="#路径三-产品-业务路线" aria-label="Permalink to &quot;路径三：产品/业务路线&quot;">​</a></h3><p><strong>描述</strong>：从技术岗转向产品岗或业务岗，利用AI技术背景做产品设计或业务运营。</p><p><strong>特点</strong>：需要补齐产品思维和商业认知，但AI背景是巨大优势。</p><p><strong>怎么走</strong>：</p><ol><li><strong>主动参与产品讨论</strong>：不要只写代码，多跟产品经理聊需求、理解用户、思考商业价值</li><li><strong>培养&quot;用户视角&quot;</strong>：技术人容易陷入&quot;技术炫技&quot;，但产品视角是&quot;解决问题&quot;</li><li><strong>考虑内部转岗</strong>：有些大公司允许技术岗内部转产品岗，可以先试试</li></ol><p><strong>天花板</strong>：产品路线的好处是可以突破&quot;写代码&quot;的天花板。好的AI产品经理年薪不比技术专家低，而且越老越懂业务越值钱。但这条路需要你真的对产品/业务感兴趣，否则会很难受。</p><h3 id="路径四-独立开发-创业路线" tabindex="-1">路径四：独立开发/创业路线 <a class="header-anchor" href="#路径四-独立开发-创业路线" aria-label="Permalink to &quot;路径四：独立开发/创业路线&quot;">​</a></h3><p><strong>描述</strong>：从打工人变成独立开发者或创业者。</p><p><strong>特点</strong>：高风险高回报，需要技术+产品+运营的全面能力。</p><p><strong>怎么走</strong>：</p><ol><li><strong>先做side project</strong>：不要一上来就辞职，先用业余时间做个小产品试试水</li><li><strong>验证市场价值</strong>：有人愿意为你的产品付钱，是检验想法的唯一标准</li><li><strong>积累原始用户</strong>：哪怕只是100个付费用户，也是从0到1的突破</li></ol><p><strong>天花板</strong>：理论上没有上限。做出一个成功的AI产品，可以实现财富自由。但失败率很高，需要你有足够的积累和风险承受能力。</p><h3 id="怎么判断自己该走哪条路" tabindex="-1">怎么判断自己该走哪条路？ <a class="header-anchor" href="#怎么判断自己该走哪条路" aria-label="Permalink to &quot;怎么判断自己该走哪条路？&quot;">​</a></h3><p>这四条路没有好坏之分，只有适合不适合。判断标准其实很简单：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是更喜欢&quot;自己搞定技术难题&quot;，还是&quot;带领团队搞定难题&quot;？</span></span>
<span class="line"><span>你是更喜欢&quot;深入研究技术&quot;，还是&quot;看技术在产品里发挥作用&quot;？</span></span>
<span class="line"><span>你是更喜欢&quot;稳定的收入&quot;，还是&quot;高风险高回报&quot;？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>没有标准答案。你的选择应该符合你的性格、兴趣和能力。</p><p>但有一点是确定的：<strong>无论走哪条路，技术基础都要扎实</strong>。技术专家靠技术吃饭，产品/管理/创业也离不开对技术的理解。</p><h3 id="_35岁危机的真相" tabindex="-1">35岁危机的真相 <a class="header-anchor" href="#_35岁危机的真相" aria-label="Permalink to &quot;35岁危机的真相&quot;">​</a></h3><p>很多人担心&quot;35岁危机&quot;，我来给你拆解一下这个焦虑。</p><p><strong>35岁危机会发生的人</strong>：</p><ul><li>技术停止成长，一直在吃老本</li><li>性价比下降，比应届生贵但能力没强多少</li><li>只懂技术，不懂业务、产品、管理</li></ul><p><strong>35岁不会危机的人</strong>：</p><ul><li>技术持续成长，在某个领域有深度积累</li><li>有行业经验和业务理解</li><li>有可迁移的软技能</li></ul><p>所以危机的本质不是&quot;年龄&quot;，而是&quot;成长停滞&quot;。</p><p><strong>你从25岁入职到35岁，有整整10年时间。这10年如果你持续成长，35岁不是终点，是起点。</strong></p><h3 id="提前规划-不要等到危机来了再应对" tabindex="-1">提前规划，不要等到危机来了再应对 <a class="header-anchor" href="#提前规划-不要等到危机来了再应对" aria-label="Permalink to &quot;提前规划，不要等到危机来了再应对&quot;">​</a></h3><p>职业规划这件事，建议从入职第一天就开始做，而不是等到35岁前才想起来。</p><p><strong>每年做一次&quot;职业复盘&quot;</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ 这一年我学到了什么新技能？</span></span>
<span class="line"><span>□ 这一年我的影响力扩大了吗？</span></span>
<span class="line"><span>□ 这一年我的市场价值提升了吗？</span></span>
<span class="line"><span>□ 明年我想达到什么状态？</span></span>
<span class="line"><span>□ 为了达到那个状态，我需要做什么？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这个问题很简单，但坚持做10年，你会发现自己跟那些&quot;混日子&quot;的人差距越来越大。</p><hr><h2 id="本章行动清单" tabindex="-1">本章行动清单 <a class="header-anchor" href="#本章行动清单" aria-label="Permalink to &quot;本章行动清单&quot;">​</a></h2><ol><li><p><strong>立刻做一次&quot;短板四象限&quot;分析</strong></p><p>拿出纸笔，列出你入职后发现的短板，按&quot;频率&quot;和&quot;急需程度&quot;分类。明确接下来一个月你最需要补什么。</p></li><li><p><strong>建立&quot;补课-工作&quot;循环</strong></p><p>每周选一个短板，用工作项目来练习。不要单独学习，学了就用，用了再学。</p></li><li><p><strong>每天花10分钟&quot;巡逻&quot;你的模块</strong></p><p>检查告警、监控、待办项。培养主动发现问题的习惯，而不是等别人告诉你。</p></li><li><p><strong>主动认领一个&quot;Owner&quot;职责</strong></p><p>选一个小模块，主动跟Leader申请负责。哪怕只是一个工具函数的管理，也是Owner意识的开始。</p></li><li><p><strong>设计你的&quot;输入-处理-输出&quot;学习系统</strong></p><p>明确你每天/每周看什么技术内容，怎么消化，怎么输出。不要让信息白白流过。</p></li><li><p><strong>选一个技术方向开始深挖</strong></p><p>不要什么都学，选一个方向深入学习。6个月后，你至少应该在一个方向上比大多数人都懂。</p></li><li><p><strong>思考你的&quot;10年后的样子&quot;</strong></p><p>不是想清楚，而是开始想。10年后你想成为什么样的人、走什么路？从现在开始积累。</p></li></ol><hr><blockquote><p><strong>下章预告</strong>：第18章我们来聊聊AI应用开发者的未来——AI会不会取代你？从应用到基础设施的进阶路径，以及长期职业规划。看看这本书的最后一章，帮你在更宏观的视角下理解自己的位置和方向。</p></blockquote>`,242)])])}const h=n(p,[["render",l]]);export{d as __pageData,h as default};
